import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.BQ1gajhD.js";const q=JSON.parse('{"title":"午门","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/wumen.md","filePath":"landmarks/forbidden-city/wumen.md","lastUpdated":1784720050000}'),l={name:"landmarks/forbidden-city/wumen.md"};function n(s,t,i,d,u,g){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="午门" tabindex="-1">午门 <a class="header-anchor" href="#午门" aria-label="Permalink to &quot;午门&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1757510146664-48b437cddd1a?w=1200&amp;q=80" alt="午门"></p><blockquote><p>五凤翼然，九门洞开。这里是紫禁城的正门，也是帝国威仪的第一道门槛。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>午门是紫禁城的正门，位于北京城中轴线的南端，因坐北朝南、居中向阳而得名&quot;午&quot;。它是故宫四座城门中最为宏伟的一座，也是整座皇宫的礼仪门户——一切国家大典的仪仗从这里开始，一切凯旋献俘的盛典在这里落幕。</p><p>午门建成于明永乐十八年（1420年），清顺治四年（1647年）重修。整座建筑由城台和城楼组成，城台高12米，正中开三门，两侧各开一掖门，形成&quot;明三暗五&quot;的格局。城台上矗立着五座重檐亭式楼阁，中央主楼面阔九间，两侧各两座方亭以廊庑相连，形如凤凰展翅，故又称&quot;五凤楼&quot;。</p><p>今天，午门是故宫博物院的唯一入口。穿过那幽深的门洞，六百年的皇家气象便在眼前铺展开来。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>通高</strong></td><td style="text-align:left;">37.95米（故宫最高的建筑之一）</td></tr><tr><td style="text-align:left;"><strong>城台高度</strong></td><td style="text-align:left;">12米</td></tr><tr><td style="text-align:left;"><strong>门洞格局</strong></td><td style="text-align:left;">明三暗五（正面三门，背面加两掖门共五门）</td></tr><tr><td style="text-align:left;"><strong>城楼形制</strong></td><td style="text-align:left;">五座重檐攒尖顶楼阁，俗称&quot;五凤楼&quot;</td></tr><tr><td style="text-align:left;"><strong>主楼面阔</strong></td><td style="text-align:left;">九间</td></tr><tr><td style="text-align:left;"><strong>两翼</strong></td><td style="text-align:left;">左右各建廊庑十三间，环抱如阙</td></tr></tbody></table><p>午门的平面设计极具巧思：城台向两侧延伸，环抱成&quot;凹&quot;字形，形成三面合围的广场空间。这种形制源自唐宋以来宫门&quot;双阙&quot;的传统，既增强了防御功能，又营造出强烈的礼仪围合感——当百官步入这片广场仰望五凤楼时，皇权的压迫感油然而生。</p><p>&quot;明三暗五&quot;的门洞各有严格的等级规定：<strong>正中门洞专供皇帝通行</strong>；皇帝大婚时，皇后的凤轿可从中门入宫，一生仅此一次；殿试揭晓后，状元、榜眼、探花三人可从中门出宫，亦仅此一次。此外，宗室王公走东侧门，文武大臣走西侧门，两掖门仅在大型朝会时按文东武西开启。一道门洞，便是帝国等级的缩影。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="推出午门斩首-——一个流传百年的误传" tabindex="-1">&quot;推出午门斩首&quot;——一个流传百年的误传 <a class="header-anchor" href="#推出午门斩首-——一个流传百年的误传" aria-label="Permalink to &quot;&quot;推出午门斩首&quot;——一个流传百年的误传&quot;">​</a></h3><p>&quot;推出午门斩首&quot;是戏曲小说中最经典的台词之一，但历史上，午门从不是刑场。明代午门确有一项令人闻之色变的刑罚——<strong>廷杖</strong>：大臣触怒皇帝，便被拖到午门外当众杖责。正德十四年（1519年），群臣谏阻明武宗南巡，一百四十六人受廷杖，当场打死十一人。廷杖之酷烈，让&quot;午门&quot;在士大夫心中蒙上了血腥色彩，久而久之便讹传为&quot;斩首&quot;之地。</p><h3 id="献俘礼-帝国的高光时刻" tabindex="-1">献俘礼：帝国的高光时刻 <a class="header-anchor" href="#献俘礼-帝国的高光时刻" aria-label="Permalink to &quot;献俘礼：帝国的高光时刻&quot;">​</a></h3><p>午门最庄严的功能是&quot;献俘礼&quot;。每逢大军凯旋，皇帝登临午门城楼，文武百官侍立两侧，战俘被押至城下献于御前。清乾隆年间平定准噶尔、大小和卓之乱后，都曾在此举行盛大的献俘仪式。彼时五凤楼上鼓乐齐鸣，城下三军山呼万岁，那是帝国武功的巅峰展示。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>五凤楼全景</strong>：从午门广场南侧回望，五座楼阁翼然展开，是紫禁城最具仪式感的画面。</li><li><strong>中门门洞</strong>：留意正中门洞上方的城楼——那是只有皇帝、皇后（一次）和状元（一次）才能通行的&quot;御道&quot;所在。</li><li><strong>凹字形广场</strong>：感受三面城台环抱的空间张力，体会古代&quot;阙&quot;制建筑的遗韵。</li><li><strong>门钉与铺首</strong>：朱红大门上纵横各九路金色门钉（共81颗），是最高等级的标志。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>最佳拍摄时间</strong>：早晨8:30开馆时人最少，站在广场南端可拍到无人的午门全景；傍晚逆光下五凤楼的剪影也极为壮观。</li><li><strong>避开高峰</strong>：上午10点至下午2点游客最密集，入口排队可能超过一小时，尽量赶早或赶晚。</li><li><strong>注意朝向</strong>：午门是故宫唯一入口，只能从南侧进入；参观结束后无法从午门出（神武门或东华门出）。</li><li><strong>门洞里的温度</strong>：厚重的城门洞内冬暖夏凉，夏天穿越门洞时会有明显的凉意。</li></ul><hr><p><strong>📍 位置</strong>：紫禁城中轴线最南端，故宫唯一入口 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/taihe-dian.html">太和殿</a>（经太和门向北） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',22)])])}const c=a(l,[["render",n]]);export{q as __pageData,c as default};
